    {
      "term": "TN-C-S System",
      "simpleDefinition": "A system where the neutral and earth are combined into a single conductor in the supply cable, but separated at the consumer's intake (cut-out).",
      "anchor": "Combined in the street, split at the house.",
      "misconception": "Thinking that neutral and earth remain joined together inside the building's internal circuits."
    },
    {
      "term": "TT System",
      "simpleDefinition": "An arrangement where the supplier does not provide an earth terminal, requiring the consumer to provide their own connection to the ground.",
      "anchor": "Your own rod in the ground.",
      "misconception": "Assuming the supplier is always responsible for providing an earth terminal for every property."
    },
    {
      "term": "CPC (Circuit Protective Conductor)",
      "simpleDefinition": "The specific conductor that connects the exposed metal parts of an electrical circuit to the main earthing terminal.",
      "anchor": "The internal path for fault current.",
      "misconception": "Confusing the CPC with 'bonding' conductors which connect to gas or water pipes."
    },
    {
      "term": "ADS (Automatic Disconnection of Supply)",
      "simpleDefinition": "A safety strategy that uses a low-resistance path and a protective device to quickly cut power during a fault.",
